var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아아- 이번에도 C급이라니. 나이엘 앞에선 아무렇지 않은 척했지만 역시 아쉽다.","JPN":"あーあー、今回もC級だなんて。ナイエルの前では何でもないふりしたけど、やっぱり気にしちゃうな。","ENG":"Ahh... Grade C again? I acted like I didn't care in front of Naielle, but it's pretty upsetting.","TWN":"可惡，這次還是C，雖然在奈爾面前裝作不在意，但還是有點難過。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 괜찮아! 내년에는 다른 결과가 나올지도 모르니까!","JPN":"でも大丈夫！　来年はまた結果が変わっているかもしれないんだし！","ENG":"But it's okay! Because next year's results could be better!","TWN":"沒關係！明年說不定會有不一樣的結果！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"카운터 등급이라는 것은… 수행에 따라 변하기도 하는 것이오?","JPN":"カウンターのランクって……修行することで変わることもあるのでしょうか？","ENG":"This Counter grade... does it change depending on your training?","TWN":"所謂的制裁者等級…是靠著修行就能夠改變的嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"물론이지! 세상엔 노력으로 바뀌지 않는 건 없어!","JPN":"もちろんだよ！　この世に努力で変えられないものはないんだから！","ENG":"Of course! There's nothing in this world that hard work can't change!","TWN":"那當然！世界上沒有什麼事是無法靠著努力改變的！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…라고 말하고 싶지만, 확신은 못하겠네.","JPN":"……って言いたいところだけど、確信はないかも。","ENG":"...Is what I want to believe, but I'm not actually sure.","TWN":"…我也很想這麼說，但事實是不一定。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"시간에 따라 힘이 꾸준히 성장하는 케이스도 있지만, 그렇지 않은 케이스가 훨씬 많거든.","JPN":"時間の経過とともに、着実に能力が成長していくパターンもあるけど、そうでないことの方が多いからね。","ENG":"There are cases where their powers steadily get more powerful, but there are even more cases where they don't.","TWN":"有些人的能力是會隨著時間而進步，但絕大部分的人好像都不是這樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"카운터인 우리도 정작 자신의 힘을 전부 이해하지 못해. 카운터의 능력에 대한 연구는 아직도 한창 진행 중이니까.","JPN":"カウンターのあたしたちですら、自分たちの力の全てを理解しているわけじゃない。カウンターの能力に関する研究はまだまだ発展途上なの。","ENG":"I mean, we're Counters, and we don't fully understand our abilities either. Experts are still researching it.","TWN":"就連身為制裁者的我們，都還無法完全知道自己的能力到哪裡，因為有關制裁者能力的研究都還在進行中。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아카데미의 학생들이 전광판의 기록에 일희일비 하는 모습을 보았소.","JPN":"アカデミーの生徒たちが電光板の記録に一喜一憂するところを見ました。","ENG":"I saw how the students got emotional about the records on the scoreboard.","TWN":"在下看到學院的學生因為螢幕上的紀錄而患得患失。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그 결과 하나가 많은 의미가 담긴 것처럼 느껴졌다오.","JPN":"あの結果が、とても大きな意味を持っていることがわかります。","ENG":"I could sense that each result had a lot of meaning to it.","TWN":"雖然只是一個結果，似乎卻代表著許多含意。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"세상일이라는 게 다 그렇잖아? 알파벳 같은 성적 하나로 주위의 시선이나 평가가 바뀌거든.","JPN":"それが世の常というものでしょう？ただのアルファベット一つで、周りからの視線や評価がひっくり返るからね。","ENG":"That's how the world works, right? People treat us differently depending on which alphabet we get.","TWN":"世界不就是這樣嗎？因為那些代表成績的英文字母，可以改變人家對你的眼光和評價。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이면세계에 나가는 사람들도, 침식재난을 마주친 사람들도, 우리 같은 C급 카운터보단 A급 카운터와 함께 있는 편이 마음 편할 테니까.","JPN":"裏世界に赴く人たちも、侵食災害に見舞われた人たちも、あたしたちみたいなC級より、A級カウンターが一緒にいた方が心強いだろうしね。","ENG":"People who go to Counterside, and others who have encountered a Corruption disaster... they'd want to have a Grade A Counter by their side rather than a Grade C like us.","TWN":"不管是去到異界，或是面對侵蝕災難時，比起我們這種C級的，大家跟A級在一起比較安心吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐어- 아쉬운 건 아쉬운 거지만. 그렇다고 너무 좌절할 필요는 없다고 생각해.","JPN":"まぁ、やるせないといえばそうだけど。そこで挫折することはないと思うな。","ENG":"Well, such is life. But I don't think we need to get frustrated about it so much.","TWN":"算啦～難過是有點難過，但也不需要因此而感到太挫折。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장님이 말했어. 아카데미가 학생들을 가르치는 목적은 카운터 등급을 높이는 게 아니라 그 사람이 가장 원하는 꿈을 찾아주는 거라고 말이야.","JPN":"生徒会長も言ってたよ。アカデミーが生徒たちを教える目的は、カウンターランクの上昇ではなく、それぞれが夢を見つけられるようサポートするためだって。","ENG":"Ms. President once said to me, that the purpose of teaching students at the Academy isn't to improve their Counter Grades, but to help them find and achieve their dreams.","TWN":"學生會長說過，學院的目的不是把學生教成很厲害的制裁者，而是幫助學生找到夢想。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"난 그 말이 밤에 빛나는 별처럼 마음에 와닿았어.","JPN":"あたしはその言葉が、すごくキラキラした星のように思えたの。","ENG":"What she told me stuck with me, and it has been guiding me like a star shining brightly in the night sky.","TWN":"那番話如同夜空中閃耀的星星那般觸動我。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래서 학생회장과 함께 다른 친구들의 꿈을 이끌어주고 싶다는 마음으로 학생회 임원이 된 거야. 내 능력과는 별개로.","JPN":"だからあたしは生徒会長と一緒に、他のみんなの夢をサポートしてあげたいと思って、生徒会役員になったんだ。自分にその能力があるかどうかじゃなくてね。","ENG":"It's also why I decided to join the Student Council. I wanted to help my friends find their dreams, regardless of my abilities.","TWN":"所以我會當學生會幹部，與我的能力無關，是因為我想和學生會長一起幫助學生找到夢想。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아하하… 다 말하고 나니 쑥스럽네. 혼자만 신나서 너무 떠들었나?","JPN":"あはは……つい語っちゃった。ちょっと夢中になりすぎたかな？","ENG":"Ah ha ha... Saying it out loud is kinda embarrassing. Did I get too excited and start rambling?","TWN":"哈哈哈…說完自己都覺得有點害羞呢，我是不是自顧自地說得太開心啦？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대의 마음은 분명 사람들을 올바른 길로 이끌 거요. 본인이 장담하오.","JPN":"貴殿の想いはきっと人々を正しい道に導くでしょう。自分が保証します。","ENG":"Your heart will lead people down the right path. I am certain of it.","TWN":"相信你的心一定可以引導學生走在正路，在下保證。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"헤헤- 빈말이라도 고마워.","JPN":"へへっ、お世辞だとしてもありがとう。","ENG":"Hehe... Thanks for the words of encouragement.","TWN":"嘿嘿，就算只是客套話還是很謝謝你。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Oh?","TWN":"嗯？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"왜 그러시오?","JPN":"どうました？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 별 건 아닌데.","JPN":"いや、別に大したことじゃないんだけど。","ENG":"No, it's nothing.","TWN":"沒事，沒什麼。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"시엘이 그렇게 해맑게 웃는 거, 처음 본 것 같아서.","JPN":"シエルちゃんがそうやって明るく笑っているところ、初めて見たなって。","ENG":"Just that, I think it's the first time I saw you smile like that.","TWN":"只是我好像是第一次看到你笑得這麼燦爛。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"처음… 이었소?","JPN":"そう……ですか？","ENG":"Was it... the first time?","TWN":"第一次…嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응! 웃는 모습의 시엘은 그라운드 원 최고 미소녀라구! 내가 장담해!","JPN":"うん！　笑顔のシエルちゃんはグラウンド・ワンいちの美少女だと思うよ！　あたしが保証する！","ENG":"Yup! You're the prettiest girl in all of Ground One when you smile, Ciel! I know it!","TWN":"對啊！希爾笑得時候是G1第一名美少女喔！我保證！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그 말을 들으니 마음 속이 간지럽혀지는 느낌이구려.","JPN":"そう言われると何だか胸の奥をくすぐられるような気分ですね。","ENG":"It feels as though your words are tickling my heart.","TWN":"聽你這麼說覺得心裡癢癢的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"후후, 그런 걸 바로 쑥스럽다고 하는 거야. 내가 <color=#ffd34c>앞으로도</color> 잔뜩 느끼게 해줄게.","JPN":"ふふ、そういうときは照れるって言うんだよ。あたしが　<color=#ffd34c>これからも</color>　もっとくすぐったくしてあげるね。","ENG":"Haha, that's called being embarrassed. I'll make you feel that a lot <color=#ffd34c>from now on</color>.","TWN":"呵呵，這就是害羞的感覺啦，我<color=#ffd34c>之後</color>會多多讓你體驗這種感覺的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앗…? 벌써 시간이 이렇게 됐네. 빨리 들어가야겠다.","JPN":"あっ……？　もうこんな時間。早く戻らなくちゃ。","ENG":"Oh...? Look at the time. We'd better head home.","TWN":"哎呀…？都這麼晚了，快回家吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼 내일 다시 보자! 오늘 밤엔 내 꿈 꿔! 그라운드 원 최고의 미소녀!","JPN":"じゃあ、また明日！　今夜はあたしの夢を見てね！　グラウンド・ワンいちの美少女ちゃん！","ENG":"Then, I'll see you tomorrow! Dream of me tonight, Ground One's prettiest girl!","TWN":"明天見囉！今晚做夢要夢到我喔！G1第一美少女！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…조심히 들어가오.","JPN":"……お気をつけて。","ENG":"...Go home safe.","TWN":"…回家小心。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"앞으로도…","JPN":"これからも……","ENG":"From now on...","TWN":"之後…"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"헉… 허억…","JPN":"はあっ……はあっ……","ENG":"*Huff...* *Huff...!*","TWN":"呼…呼呼…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"젠장. 나보고 어쩌라는 거야. 내가 뭘 어떻게 하면 되는 거냐고.","JPN":"くそ。何なんだよ。いったい俺にどうしろってんだ。","ENG":"Dammit. What do you want? What am I supposed to do?!","TWN":"該死！到底想要我怎樣？我到底該怎麼做！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"익숙한 냄새가 나서 와보았더니. 그대였구려.","JPN":"知っている匂いがしたので来てみれば、貴殿でしたか。","ENG":"It is you. I knew the scent was familiar.","TWN":"我聞到熟悉的味道就過來看看，原來是你。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…신입생?! 냄새라니?","JPN":"……新入生！？　匂いって何だ？","ENG":"...New kid?! What do you mean, scent?","TWN":"…新生？什麼味道？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그, 그건 그렇고… 이 시간에 학교엔 어쩐 일이야?","JPN":"と、というか……こんな時間にどうして学校にいるんだよ。","ENG":"A-anyway... what are you doing at school this late?","TWN":"先不說這個…這個時間你怎麼還在學校？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 낮 동안은 눈앞이 흐리지만, 밤에는 모든 것이 선명해진다오.","JPN":"自分は昼間はぼやけて見えますが、夜は全てが鮮明に見えるのです。","ENG":"I may not be able to see during the day, but my vision is clear at night.","TWN":"在下白天雖然視力不佳，但晚上的話一切都變得清清楚楚。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그러니 날이 밝기 전에 아카데미 곳곳을 돌아다니며 지형지물을 익혀 두는 것이지.","JPN":"だから日が昇る前にアカデミーのあちこちに行って、地形を覚えているのです。","ENG":"So I was familiarizing myself with the Academy's various structures before the sun rose.","TWN":"所以就趁著天亮之前，在學院到處走走，熟悉一下地形跟環境。 "},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"밤에만 잘 보이다니. 그거 참 신기한 체질이네.","JPN":"夜の方が良く見えるなんて。どんな体質なんだか。","ENG":"You can only see clearly during the night? That's a weird quirk if you ask me.","TWN":"只有晚上才看得清楚？真是奇特的體質。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대는 나무를 단련대 삼아 힘을 기르고 있던 것이오?","JPN":"貴殿は木を相手に鍛錬をしていたのですか？","ENG":"Were you developing your strength through training with that wooden dummy?","TWN":"你是在用木人樁來培養自己的實力嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"쳇… 고작 나무 때리는 걸로 힘이 길러질 리가 있나.","JPN":"ちぇっ……木を殴るだけで鍛錬になるわけないだろ。","ENG":"Tch... hitting a wooden dummy won't make anyone stronger.","TWN":"嘖…打個木人樁有什麼好培養實力的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그냥 답답한 일이 있어서… 화풀이였을 뿐이야.","JPN":"ただ鬱憤晴らしに……暴れていただけだ。","ENG":"I just have a lot on my mind... so I'm letting off some steam.","TWN":"我只是心裡很煩…所以打木頭出氣。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"나이엘이라면 단칼에 잘라버렸겠지만, D급인 나한텐 평생 어림도 없는 일이라고.","JPN":"ナイエルだったら一撃で切り倒していたんだろうけど、D級の俺にはそんなのできるわけもない。","ENG":"If it were Naielle, she would've sliced this dummy up in half. But for a Grade D Counter like me, not in a million years.","TWN":"要是奈爾應該會一刀砍斷木頭吧？這是我這個D級一輩子也辦不到的事！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그런 힘을 얻는 것이, 그대의 꿈인 거요?","JPN":"そういう力を手に入れることが、貴殿の願いなのですか？","ENG":"Is it your dream to obtain such power?","TWN":"你的夢想，是得到那種力量嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"힘이 없으면 꿈도 갖지 못해. 그게 현실이니까.","JPN":"力なき者は、願いを持つことすら許されない。それが現実だ。","ENG":"You can't dream of anything unless you have power. That's the real world for you.","TWN":"一個沒能力的人連作夢都沒資格，這就是現實！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"힘도 없는 D급 카운터에게 꿈 같은 건 가당치도 않은 얘기야.","JPN":"力のないD級カウンターにとって、夢を持つなんて、それこそ夢のまた夢のような話なのさ。","ENG":"For a weak Grade D Counter like me, dreams are a luxury.","TWN":"對一個沒能力的D級制裁者談什麼夢想。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인이 그대의 꿈을 위해 도울 수 있는 일은 없겠소?","JPN":"貴殿の願いのために、自分がお手伝いできることはありますか？","ENG":"Is there anything I can do to assist you in achieving your dream?","TWN":"在下可以為你的夢想做些什麼嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…응? 네가 갑자기 왜?","JPN":"……え？　いきなりどうして？","ENG":"...Hmm? What's going on?","TWN":"…蛤？為何突然這麼問？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 학생회 임원이나 다른 스승들처럼 누군가를 가르치거나 이끄는 재주는 없다오.","JPN":"自分は生徒会の役員や、師匠の方々のように、誰かを教え、導くような才能は持ち合わせていません。","ENG":"Unlike the Student Council members or masters, I am not talented in teaching others.","TWN":"在下不像學生會幹部或是師父一樣有教導人的天分。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"하지만, 같은 처지의 교우로서 돕는 것 정도라면 할 수 있을 거요.","JPN":"ですが、同じ立場である学友と肩を並べながら切磋琢磨することはできます。","ENG":"However, I am capable of helping a fellow classmate.","TWN":"不過身為同學，幫個忙還是可以的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그럼, 내일 점심에 테마파크로 나와줄 수 있어?","JPN":"じゃあ、明日の昼、テーマパークに来てくれないか？","ENG":"Then, could you come out to the amusement park at lunchtime tomorrow?","TWN":"那你明天中午可以來主題公園一趟嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"테마파크가 무엇이오?","JPN":"テーマパークとは何でしょう？","ENG":"What is an amusement park?","TWN":"主題公園是什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"응? 그런 것도 몰라?","JPN":"え？　テーマパークを知らない？","ENG":"Hmm? You don't know?","TWN":"什麼？你連主題公園都不知道喔？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"으음… 그러니까… 사람들이 다 함께 모여서 노는 곳이야. 평소엔 엄청 시끌벅적해. 커다란 관람열차도 있고, 롤러코스터도 있고…","JPN":"うーん……そうだな……たくさんの人が集まって遊ぶところだよ。普段はすごくにぎやかで、大きな観覧車があったり、ジェットコースターがあったり……","ENG":"Well... let's see... It's a place where people gather to have fun. It's always bustling with people, and they have this huge Ferris wheel and roller coasters…","TWN":"嗯…就是…大家聚在一起玩樂的地方。平常人超多的，裡面有超長遊園列車，還有雲霄飛車…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대는 그런 장소에서 수련을 하려는 거요?","JPN":"貴殿はそのような場所で修行をするのですか？","ENG":"It is your training grounds?","TWN":"你在那種地方修練嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"거긴… 아주 예전에 일어난 침식현상 때문에 문을 닫았거든.","JPN":"あそこは……大昔に起きた侵食現象のせいで今はもう閉園してるんだ。","ENG":"It's... a place that closed down a long time ago due to the Counterside Effect.","TWN":"那裡…很久以前發生過侵蝕現象，早就關門大吉了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"아직 1종 침식체가 나타난다는 소문이 있던데, 그게 사실이라면 학교에서 배운대로 침식체와 한 번 싸워보고 싶어.","JPN":"まだ1種、侵食体が出るって噂があるんだけど、もしそれが本当なら、学校で習った内容で侵食体と実際に戦ってみたい。","ENG":"There are rumors that Category 1 C.O.s can still be found residing there. If that's true, I want to use what I learned at school and fight a C.O.","TWN":"我聽說現在還會出現1類侵蝕體，如果是真的，那我想用學校教的對付侵蝕體看看。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"보충수업인 셈 치고… 네가 함께 동행해준다면 든든할 것 같아서.","JPN":"課外学習のつもりで……お前が一緒に来てくれるなら、心強いかなって。","ENG":"Let's just think of it as a make-up class... I think I'll be more confident if you come with me.","TWN":"就當作是課後輔導…你也一起去的話，我會比較安心。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…알겠소. 그리 하리다.","JPN":"……承知しました。そうしましょう。","ENG":"...Very well. I shall accompany you.","TWN":"…好的，在下會去。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오늘이군요.","JPN":"いよいよ今日ですね。","ENG":"Today is the day.","TWN":"就是今天。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양이 약속한 오늘 해가 지기 전까지 사태를 해결하지 못한다면… 저격사건의 범인은 학생회의 방식대로 처리하겠습니다.","JPN":"今日の夕方までに事態を解決するというシエルさんの約束が遂行されない場合……狙撃事件の犯人は生徒会の意向で処理します。","ENG":"If you are unable to solve the situation by yourself... the Student Council will step in and handle the culprit of the shooting case.","TWN":"我們說好在今天日落前，你若無法把事情處理好…那我就會用學生會的方式來處理狙擊事件的犯人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"명심해두겠소.","JPN":"承知しました。","ENG":"Understood.","TWN":"在下知道。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양에게… 아카데미 생활은 잘 맞던가요?","JPN":"シエルさん……アカデミーでの生活はいかがでしたか？","ENG":"Ciel... what do you think about your school life so far?","TWN":"希爾同學…你還適應學生活嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어제는 선생으로부터 침식체와 싸우는 법의 기초론을 배우고, 꽃을 좋아하는 낭자와 함께 모종삽으로 벤자민 씨앗을 심었다오.","JPN":"昨日は教師から侵食体との戦闘における基礎を学び、花好きの娘とともにスコップでベンジャミンの種を植えました。","ENG":"Yesterday, the teacher taught us the introductory theory of how to fight C.O.s, and planted Benjamin seeds with a small maiden who loves flowers.","TWN":"昨天在跟老師學對付侵蝕體的基礎概論，還和喜歡花的小姑娘一起種垂榕。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"고향에선 배우지 못한 것들을 경험할 수 있어 하루하루가 유익하고 새롭소.","JPN":"故郷では学んでこなかった新しい経験が色々できて、非常に新鮮でためになる毎日です。","ENG":"Being able to do things that I could not do at home has made each day interesting and beneficial.","TWN":"在這裡可以體驗到老家學不到的東西，每天都覺得很新鮮又充實。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇다면 다행이네요. 다른 학생들과도 잘 지내는 것 같더군요.","JPN":"それはなによりです。他の生徒たちとも上手くやれているようで。","ENG":"I am glad to hear that. You seem to be doing well with the other students.","TWN":"那就好，我看你和其他同學好像也相處得不錯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만…","JPN":"ですが……","ENG":"However...","TWN":"不過…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양은 누구에게 그것을 배웠는지, 누구와 했는지, 사람의 이름은 단 한 번도 말하지 않는 것 같네요.","JPN":"シエルさんは教師の名前も、一緒に種を植えた相手の名前も、言わないんですね。","ENG":"I do not think I have ever heard you refer to anyone by name, whether it be whom you learned something from or who you were with.","TWN":"我發現，不管是和誰學什麼，或是和誰做什麼，你都絕口不提對方的名字。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"타인의 이름을 되새기고 부르는 순간, 정이란 것을 갖고 나약해지기 때문이라오.","JPN":"誰かの名前を思い出し、口にした瞬間、情が生まれ、人は軟弱になります。","ENG":"That is because the moment one refers to others by their names, the emotional attachment will make one weak.","TWN":"因為當你記住別人的名字並且喊出來的瞬間，就會開始產生感情，就是變弱的開始。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이름을 부른다는 건 그 사람과 연을 이어 나가는 과정이죠.","JPN":"名前を呼ぶことは、その人との縁を繋いでいくことにもなりますよ。","ENG":"But calling each other by name is a process of making connections with people.","TWN":"喊名字是和別人建立關係的過程。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"혹시 시엘 양은, 아무에게도 마음을 줄 수 없는 사람인가요?","JPN":"もしかしてシエルさんは、他人に心を許すことができないのでしょうか？","ENG":"Ciel, are you not able to open your heart to others?","TWN":"希爾同學是無法對任何人敞開心的人嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇게 하는 것이 은인의 가르침이기에, 그것을 따르고 있을 뿐이오.","JPN":"恩人からそう教わったので、従っているまでです。","ENG":"I follow this rule, for it was my master's teaching.","TWN":"這是恩人的教訓，在下只是聽從教訓而已。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양의 뜻이 그렇다면… 알겠습니다.","JPN":"シエルさんがそうおっしゃるのでしたら……わかりました。","ENG":"If that is your decision, Ciel... I understand.","TWN":"好吧…如果你是這麼想的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 저는 이름을 부르는 것이 사람을 나약하게 만든다고 생각하지 않아요. 오히려 그 반대죠.","JPN":"ですが私は、誰かの名前を呼ぶことは、その人自身を弱くするどころか、強くしてくれると思っています。","ENG":"But I do not believe that calling someone by name will make you weak. Rather, it is the opposite.","TWN":"但我不認為喊人家的名字會使自己變弱，反而是相反的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양에게 이름을 지어주신 분이 있다면, 그분도 그런 생각이 아니었을까요?","JPN":"シエルさんに名前を付けてくださった方がいるなら、同じことを考えていたんじゃないでしょうか？","ENG":"Whoever gave you your name, do you not think that person would agree?","TWN":"我想給你這個名字的人也是這麼的吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대는 본인의 은인과 닮았으면서도… 닮지 않았구려.","JPN":"貴殿は自分の恩人と似ているようで……似ていませんね。","ENG":"You resemble my master... and do not at the same time.","TWN":"你和在下的恩人有點像…又不太像。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하나의 표현에도 여러 뜻이 있는 것처럼, 똑같은 사람이란 건 없으니까요.","JPN":"一つの言葉にも、いくつも意味があるように、全く同じ人間なんて存在しませんから。","ENG":"Just like how one expression can contain multiple meanings, no person is the same.","TWN":"一句話可以有很多解讀，人也沒有完全相像的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대는 잘못을 저지른 학생들을 규칙에 따라 처벌하지 않고 관용을 베풀었지.","JPN":"貴殿は過ちを犯した生徒を、ルールに従って罰するのではなく、寛大な処置を下しました。","ENG":"You made a decision not to punish the students who violated the rules and instead showed them generosity.","TWN":"你沒有懲罰犯錯的學生，而是選擇包容。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그 결정을 후회하진 않소?","JPN":"その決定を……後悔してはいないのでしょうか？","ENG":"Do you regret making that decision?","TWN":"你會對你的決定感到後悔嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"후회는 두렵지 않아요. 그저 모두에게 평등한 기회를 주고 싶을 뿐이죠.","JPN":"後悔することを畏れてはいません。ただ全員に平等なチャンスが与えられればいいと思っているだけです。","ENG":"I do not fear regret. All I wanted was to give everyone an equal opportunity.","TWN":"我不害怕後悔，我只是想給每個人公平的機會。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제가 아는 두 사람이라면… 마지막엔 결국 옳은 판단을 할 거라고 믿어요.","JPN":"私の知る二人なら……きっと最後は正しい判断を下してくれるはずだと信じています。","ENG":"For the two students I know... I firmly believe that they will eventually make the right decision.","TWN":"若是是我認識的二個人…那我相信他們最後還是會做出正確的判斷的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"일어나려는 건가요? 차는 아직 남았습니다만.","JPN":"もう帰られるのですか？　お茶がまだ残っていますよ。","ENG":"Are you leaving already? But there is some tea left.","TWN":"你要走了嗎？茶還沒喝完呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이 정도면 충분하오. 약속한 시간이 얼마 남지 않았으니, 이만 가보리다.","JPN":"もう十分です。約束の時間も迫っているので、今日はこの辺で失礼します。","ENG":"That is enough for me. I must leave, for it is almost time for my next arrangement.","TWN":"差不多了，距離約定的時間剩不到幾小時，在下先行告辭。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다음 저녁도…","JPN":"明日の夕飯も……","ENG":"I hope...","TWN":"希望…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"함께 먹을 수 있으면 좋겠네요.","JPN":"一緒にできるといいですね。","ENG":"We can have dinner again sometime.","TWN":"下次可以一起吃飯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그때는 케이크로 부탁하오.","JPN":"その時はケーキをお願いします。","ENG":"When the time comes, I will count on you to bring cake.","TWN":"到時候請準備蛋糕。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 차보다, 케이크의 달콤함이 좋소.","JPN":"自分はお茶より、甘いケーキの方が好みなので。","ENG":"I prefer the sweetness of cake over tea.","TWN":"在下比較喜歡蛋糕的甜味勝過茶。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};